 26→/**
 27→ * <p>
 28→ * Mybatis-plus Config.
 29→ * </p>
 30→ *
 31→ * @author Shawn Deng
 32→ */
 33→@Configuration(proxyBeanMethods = false)
 34→@EnableTransactionManagement
 35→@MapperScan(basePackages = {"com.yottastudios.ns.collabspace.*.mapper"})
 36→@Slf4j
 37→public class MybatisPlusConfig {
 38→
 39→    @Value("${DATABASE_TABLE_PREFIX:collabspace_}")
 40→    private String dbTablePrefix;
 41→
 42→    /**
 43→     * config mybatis-plus interceptor.
 44→     *
 45→     * @return MybatisPlusInterceptor
 46→     */
 47→    @Bean
 48→    public MybatisPlusInterceptor mybatisPlusInterceptor() {
 49→        MybatisPlusInterceptor interceptor = new MybatisPlusInterceptor();
 50→        interceptor.addInnerInterceptor(new PaginationInnerInterceptor());
 51→        interceptor.addInnerInterceptor(new OptimisticLockerInnerInterceptor());
 52→        return interceptor;
 53→    }
 54→
 55→    /**
 56→     * mybatis configuration customizer.
 57→     *
 58→     * @return ConfigurationCustomizer
 59→     */
 60→    @Bean
 61→    public ConfigurationCustomizer configurationCustomizer() {
 62→        return configuration -> {
 63→            configuration.setObjectWrapperFactory(new MybatisMapWrapperFactory());
 64→            configuration.setCacheEnabled(false);
 65→        };
 66→    }
 67→
 68→    /**
 69→     * mybatis-plus properties customizer.
 70→     *
 71→     * @return MybatisPlusPropertiesCustomizer
 72→     */
 73→    @Bean
 74→    public MybatisPlusPropertiesCustomizer mybatisPlusPropertiesCustomizer() {
 75→        return properties -> {
 76→            properties.getGlobalConfig().setBanner(false);
 77→            properties.getGlobalConfig().getDbConfig().setTablePrefix(dbTablePrefix);
 78→            Properties customProperties = new Properties();
 79→            customProperties.setProperty("tablePrefix", dbTablePrefix);
 80→            properties.setConfigurationProperties(customProperties);
 81→            properties.setCheckConfigLocation(true);
 82→            properties.getGlobalConfig().getDbConfig().setUpdateStrategy(FieldStrategy.NOT_EMPTY);
 83→            properties.setMapperLocations(new String[] {"classpath*:/mapper/**/*.xml",
 84→                "classpath*:/enterprise/mapper/**/*.xml"});
 85→        };
 86→    }
 87→
 88→    /**
 89→     * customizer sql injector.
 90→     *
 91→     * @return sql injector
 92→     */
 93→    @Bean
 94→    public DefaultSqlInjector expandSqlInjector() {
 95→        // Support batch insertion
 96→        return new DefaultSqlInjector() {
 97→            @Override
 98→            public List<AbstractMethod> getMethodList(Class<?> mapperClass, TableInfo tableInfo) {
 99→                List<AbstractMethod> methodList = super.getMethodList(mapperClass, tableInfo);
100→                InsertBatchSomeColumn insertBatchSomeColumn = new InsertBatchSomeColumn(
101→                    t -> !StrUtil.equalsAny(t.getProperty(), "createdAt", "updatedAt",
102→                        "isDeleted"));
103→                methodList.add(insertBatchSomeColumn);
104→                return methodList;
105→            }
106→        };
107→    }
108→}
