299→    //发送响应流方法
300→    public void setResponseHeader(HttpServletRequest request,HttpServletResponse response, String fileName) {
301→        try {
302→            response.setContentType("application/vnd.openxmlformats-officedocument.spreadsheetml.sheet");
303→            response.setCharacterEncoding("UTF-8");
304→
305→
306→            String userAgent = request.getHeader("User-Agent");
307→            String encodedFileName;
308→
309→            if (userAgent != null && userAgent.contains("MSIE")) {
310→                // IE浏览器
311→                encodedFileName = URLEncoder.encode(fileName, StandardCharsets.UTF_8);
312→            } else if (userAgent != null && userAgent.contains("Firefox")) {
313→                // Firefox浏览器
314→                encodedFileName = new String(fileName.getBytes(StandardCharsets.UTF_8), "ISO8859-1");
315→            } else {
316→                // Chrome、Safari等现代浏览器
317→                encodedFileName = URLEncoder.encode(fileName, StandardCharsets.UTF_8).replaceAll("\\+", "%20");
318→            }
319→
320→            response.setHeader("Content-Disposition",
321→                    "attachment;filename=\"" + encodedFileName + ".xlsx\"");
322→
323→            // 缓存控制
324→            response.addHeader("Pragma", "no-cache");
325→            response.addHeader("Cache-Control", "no-cache");
326→        } catch (Exception ex) {
327→            log.error("Exception :",ex);
328→        }
329→    }
